const DIRECTION = {
    UP: { x: 0, y: -1 },
    DOWN: { x: 0, y: 1 },
    LEFT: { x: -1, y: 0 },
    RIGHT: { x: 1, y: 0 }
};

// 颜色常量
const COLORS = {
    SNAKE_HEAD: '#4CAF50',
    SNAKE_BODY: '#8BC34A',
    FOOD: '#FF5722',
    BACKGROUND: '#2C3E50',
    GRID: '#34495E',
    TEXT: '#ECF0F1'
