/**
 * 贪吃蛇游戏 - 简化版本
 */

const GRID_SIZE = 20;
const CANVAS_WIDTH = 600;
const CANVAS_HEIGHT = 600;
const GRID_WIDTH = CANVAS_WIDTH / GRID_SIZE;
const GRID_HEIGHT = CANVAS_HEIGHT / GRID_SIZE;

const GAME_STATE = {
    MENU: 'menu',
    PLAYING: 'playing',
    PAUSED: 'paused',
    GAME_OVER: 'game_over'
};

const DIRECTION = {
    UP: { x: 0, y: -1 },
    DOWN: { x: 0, y: 1 },
    LEFT: { x: -1, y: 0 },
    RIGHT: { x: 1, y: 0 }
};

class Snake {
    constructor() {
        this.reset();
    }

    reset() {
        this.segments = [
            { x: Math.floor(GRID_WIDTH / 2), y: Math.floor(GRID_HEIGHT / 2) },
            { x: Math.floor(GRID_WIDTH / 2) - 1, y: Math.floor(GRID_HEIGHT / 2) },
            { x: Math.floor(GRID_WIDTH / 2) - 2, y: Math.floor(GRID_HEIGHT / 2) }
        ];
        this.direction = DIRECTION.RIGHT;
        this.nextDirection = DIRECTION.RIGHT;
    }

    move() {
        this.direction = this.nextDirection;
        const head = this.segments[0];
        const newHead = {
            x: head.x + this.direction.x,
            y: head.y + this.direction.y
        };
        this.segments.unshift(newHead);
        return this.segments.pop();
    }

    grow() {
        const tail = this.segments[this.segments.length - 1];
        this.segments.push({ x: tail.x, y: tail.y });
    }

    setDirection(newDirection) {
        if (
            (newDirection === DIRECTION.UP && this.direction !== DIRECTION.DOWN) ||
            (newDirection === DIRECTION.DOWN && this.direction !== DIRECTION.UP) ||
            (newDirection === DIRECTION.LEFT && this.direction !== DIRECTION.RIGHT) ||
            (newDirection === DIRECTION.RIGHT && this.direction !== DIRECTION.LEFT)
        ) {
            this.nextDirection = newDirection;
        }
    }

    checkCollision() {
        const head = this.segments[0];
        if (head.x < 0 || head.x >= GRID_WIDTH || head.y < 0 || head.y >= GRID_HEIGHT) {
            return true;
        }
        for (let i = 1; i < this.segments.length; i++) {
            if (head.x === this.segments[i].x && head.y === this.segments[i].y) {
                return true;
            }
        }
        return false;
    }

    getHead() {
        return this.segments[0];
    }
}

class Food {
    constructor() {
        this.position = { x: 0, y: 0 };
        this.generate();
    }

    generate(snakeSegments = []) {
        let newPosition;
        let validPosition = false;
        while (!validPosition) {
            newPosition = {
                x: Math.floor(Math.random() * GRID_WIDTH),
                y: Math.floor(Math.random() * GRID_HEIGHT)
            };
            validPosition = true;
            for (const segment of snakeSegments) {
                if (segment.x === newPosition.x && segment.y === newPosition.y) {
                    validPosition = false;
                    break;
                }
            }
        }
        this.position = newPosition;
    }

    getPosition() {
        return this.position;
    }
}

class Game {
    constructor() {
        this.canvas = document.getElementById('game-canvas');
        this.ctx = this.canvas.getContext('2d');
        this.snake = new Snake();
        this.food = new Food();
        this.score = 0;
        this.highScore = localStorage.getItem('snakeHighScore') || 0;
        this.state = GAME_STATE.MENU;
        this.gameLoop = null;
        this.speed = 150;

        this.init();
    }

    init() {
        document.getElementById('high-score').textContent = this.highScore;

        document.addEventListener('keydown', (e) => {
            switch (e.key) {
                case 'ArrowUp': this.snake.setDirection(DIRECTION.UP); break;
                case 'ArrowDown': this.snake.setDirection(DIRECTION.DOWN); break;
                case 'ArrowLeft': this.snake.setDirection(DIRECTION.LEFT); break;
                case 'ArrowRight': this.snake.setDirection(DIRECTION.RIGHT); break;
                case ' ':
                    if (this.state === GAME_STATE.PLAYING) this.pause();
                    else if (this.state === GAME_STATE.PAUSED) this.resume();
                    break;
                case 'Enter':
                    if (this.state === GAME_STATE.MENU || this.state === GAME_STATE.GAME_OVER) this.start();
                    break;
            }
        });

        document.getElementById('start-btn').addEventListener('click', () => this.start());
        document.getElementById('pause-btn').addEventListener('click', () => {
            if (this.state === GAME_STATE.PLAYING) this.pause();
            else if (this.state === GAME_STATE.PAUSED) this.resume();
        });
        document.getElementById('reset-btn').addEventListener('click', () => this.reset());
        document.getElementById('restart-btn').addEventListener('click', () => this.start());

        this.draw();
        this.updateButtonStates();
    }

    start() {
        if (this.state === GAME_STATE.PLAYING) return;
        this.state = GAME_STATE.PLAYING;
        this.score = 0;
        this.speed = 150;
        this.snake.reset();
        this.food.generate(this.snake.segments);
        document.getElementById('current-score').textContent = this.score;
        document.getElementById('game-over').style.display = 'none';
        if (this.gameLoop) clearInterval(this.gameLoop);
        this.gameLoop = setInterval(() => this.update(), this.speed);
        this.updateButtonStates();
    }

    pause() {
        if (this.state !== GAME_STATE.PLAYING) return;
        this.state = GAME_STATE.PAUSED;
        clearInterval(this.gameLoop);
        this.gameLoop = null;
        this.updateButtonStates();
    }

    resume() {
        if (this.state !== GAME_STATE.PAUSED) return;
        this.state = GAME_STATE.PLAYING;
        this.gameLoop = setInterval(() => this.update(), this.speed);
        this.updateButtonStates();
    }

    reset() {
        this.state = GAME_STATE.MENU;
        this.score = 0;
        this.speed = 150;
        this.snake.reset();
        this.food.generate(this.snake.segments);
        document.getElementById('current-score').textContent = this.score;
        document.getElementById('game-over').style.display = 'none';
        if (this.gameLoop) {
            clearInterval(this.gameLoop);
            this.gameLoop = null;
        }
        this.draw();
        this.updateButtonStates();
    }

    update() {
        this.snake.move();
        if (this.snake.checkCollision()) {
            this.gameOver();
            return;
        }
        const head = this.snake.getHead();
        const foodPos = this.food.getPosition();
        if (head.x === foodPos.x && head.y === foodPos.y) {
            this.snake.grow();
            this.food.generate(this.snake.segments);
            this.score += 10;
            if (this.score % 50 === 0 && this.speed > 50) {
                this.speed -= 10;
                clearInterval(this.gameLoop);
                this.gameLoop = setInterval(() => this.update(), this.speed);
            }
            document.getElementById('current-score').textContent = this.score;
        }
        this.draw();
    }

    draw() {
        this.ctx.fillStyle = '#2C3E50';
        this.ctx.fillRect(0, 0, CANVAS_WIDTH, CANVAS_HEIGHT);

        this.ctx.strokeStyle = '#34495E';
        this.ctx.lineWidth = 0.5;
        for (let x = 0; x <= CANVAS_WIDTH; x += GRID_SIZE) {
            this.ctx.beginPath();
            this.ctx.moveTo(x, 0);
            this.ctx.lineTo(x, CANVAS_HEIGHT);
            this.ctx.stroke();
        }
        for (let y = 0; y <= CANVAS_HEIGHT; y += GRID_SIZE) {
            this.ctx.beginPath();
            this.ctx.moveTo(0, y);
            this.ctx.lineTo(CANVAS_WIDTH, y);
            this.ctx.stroke();
        }

        const foodPos = this.food.getPosition();
        const foodX = foodPos.x * GRID_SIZE;
        const foodY = foodPos.y * GRID_SIZE;
        this.ctx.fillStyle = '#FF5722';
        this.ctx.fillRect(foodX + 2, foodY + 2, GRID_SIZE - 4, GRID_SIZE - 4);

        this.snake.segments.forEach((segment, index) => {
            const x = segment.x * GRID_SIZE;
            const y = segment.y * GRID_SIZE;
            if (index === 0) {
                this.ctx.fillStyle = '#4CAF50';
            } else {
                this.ctx.fillStyle = '#8BC34A';
            }
            this.ctx.fillRect(x + 2, y + 2, GRID_SIZE - 4, GRID_SIZE - 4);
        });

        if (this.state === GAME_STATE.PAUSED) {
            this.ctx.fillStyle = 'rgba(0, 0, 0, 0.7)';
            this.ctx.fillRect(0, 0, CANVAS_WIDTH, CANVAS_HEIGHT);
            this.ctx.font = 'bold 48px Arial';
            this.ctx.fillStyle = '#FFF';
            this.ctx.textAlign = 'center';
            this.ctx.textBaseline = 'middle';
            this.ctx.fillText('游戏暂停', CANVAS_WIDTH / 2, CANVAS_HEIGHT / 2);
        }
    }

    gameOver() {
        this.state = GAME_STATE.GAME_OVER;
        clearInterval(this.gameLoop);
        this.gameLoop = null;
        if (this.score > this.highScore) {
            this.highScore = this.score;
            localStorage.setItem('snakeHighScore', this.highScore);
            document.getElementById('high-score').textContent = this.highScore;
        }
        document.getElementById('final-score').textContent = this.score;
        document.getElementById('game-over').style.display = 'flex';
        this.updateButtonStates();
    }

    updateButtonStates() {
        const startBtn = document.getElementById('start-btn');
        const pauseBtn = document.getElementById('pause-btn');
        const resetBtn = document.getElementById('reset-btn');

        switch (this.state) {
            case GAME_STATE.MENU:
                startBtn.innerHTML = '<i class="fas fa-play"></i> 开始游戏';
                startBtn.disabled = false;
                pauseBtn.disabled = true;
                resetBtn.disabled = true;
                break;
            case GAME_STATE.PLAYING:
                startBtn.innerHTML = '<i class="fas fa-play"></i> 游戏中...';
                startBtn.disabled = true;
                pauseBtn.innerHTML = '<i class="fas fa-pause"></i> 暂停';
                pauseBtn.disabled = false;
                resetBtn.disabled = false;
                break;
            case GAME_STATE.PAUSED:
                startBtn.innerHTML = '<i class="fas fa-play"></i> 继续';
                startBtn.disabled = false;
                pauseBtn.innerHTML = '<i class="fas fa-play"></i> 继续';
                pauseBtn.disabled = false;
                resetBtn.disabled = false;
                break;
            case GAME_STATE.GAME_OVER:
                startBtn.innerHTML = '<i class="fas fa-redo"></i> 重新开始';
                startBtn.disabled = false;
                pauseBtn.disabled = true;
                resetBtn.disabled = false;
                break;
        }
    }
}

window.addEventListener('DOMContentLoaded', () => {
    const game = new Game();
    window.snakeGame = game;
    console.log('贪吃蛇游戏已加载！');
});
